// specialists/env-vars.js — Checks if sensitive configuration uses environment variables

import { RepoType } from '../contract.js';

export const checkId = 'env-vars';
export const name = 'Environment Variables';
export const appliesTo = ['all'];

function scoreFile(path) {
  const base = path.split('/').pop().toLowerCase();
  let score = 0;
  const entries = ['index','main','server','app','config','entry','start','cli','bin','build','core','runtime','compiler','bootstrap','factory','application','program','command'];
  if (entries.some(n => base.includes(n))) score += 5;
  const configs = ['webpack.config','rollup.config','vite.config','babel.config','.babelrc','tsup.config','esbuild.config','next.config','nuxt.config','astro.config','vue.config','svelte.config','remix.config','gatsby.config','eleventy.config','parcel.config','rspack.config','turbo.config','unbuild.config'];
  if (configs.some(n => base.includes(n))) score += 4;
  if (!path.includes('/')) score += 2;
  if (/^(src|lib|app|bin|server|api|packages|apps|libs|cli|core|tools|scripts)\//.test(path)) score += 1;
  return score;
}

function isTestFile(path) {
  if (/(^|\/)test(s|ing)?\//.test(path)) return true;
  if (/(^|\/)__tests__?\//.test(path)) return true;
  if (/(^|\/)spec(s|ification)?\//.test(path)) return true;
  if (/(^|\/)__mocks__\//.test(path)) return true;
  if (/(^|\/)__fixtures__\//.test(path)) return true;
  if (/(^|\/)e2e\//.test(path)) return true;
  if (/(^|\/)integration\//.test(path)) return true;
  if (/(^|\/)benchmark(s)?\//.test(path)) return true;
  const base = path.split('/').pop();
  if (/^(jest|vitest|karma|playwright|cypress)\.config\./.test(base)) return true;
  if (/\.(test|spec|e2e)\.(js|ts|jsx|tsx|mjs|cjs)$/.test(path)) return true;
  return false;
}

function isInsideString(line, matchIndex) {
  let s = false, d = false, b = false;
  for (let i = 0; i < matchIndex; i++) {
    const c = line[i];
    if (c === '\\') { i++; continue; }
    if (c === "'" && !d && !b) s = !s;
    if (c === '"' && !s && !b) d = !d;
    if (c === '`' && !s && !d) b = !b;
  }
  return s || d || b;
}

const ENV_PATTERNS = [
  { regex: /process\.env\b/g, name: 'process.env' },
  { regex: /import\.meta\.env\b/g, name: 'import.meta.env' },
  { regex: /Deno\.env\b/g, name: 'Deno.env' },
  { regex: /Bun\.env\b/g, name: 'Bun.env' },
];

function findEnvUsage(content) {
  const lines = content.split('\n');
  for (const line of lines) {
    for (const { regex, name } of ENV_PATTERNS) {
      const r = new RegExp(regex.source, 'g');
      let m;
      while ((m = r.exec(line)) !== null) {
        if (!isInsideString(line, m.index)) return name;
      }
    }
  }
  return null;
}

async function scanFiles(fileList, files) {
  let foundPattern = null;
  let foundDotenvSetup = false;
  for (const fp of fileList) {
    try {
      const c = await files.get(fp);
      if (!c) continue;
      const p = findEnvUsage(c);
      if (p && !foundPattern) foundPattern = p;
      if (/require\(['"]dotenv['"]\)/.test(c) || /import\s+.*dotenv/.test(c) || /dotenv\.config/.test(c)) foundDotenvSetup = true;
      if (foundPattern) break;
    } catch (e) {}
  }
  return { foundPattern, foundDotenvSetup };
}

function buildFileList(tree, limit) {
  return tree
    .filter(p => !p.includes('node_modules') && /\.(js|ts|jsx|tsx|mjs|cjs)$/.test(p) && !/\.d\.ts$/.test(p) && !isTestFile(p))
    .sort((a, b) => scoreFile(b) - scoreFile(a))
    .slice(0, limit);
}

export async function check(context) {
  const { tree, files, packageJson, repoType } = context;

  try {
    if (repoType === RepoType.EMPTY) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Empty repo — no env vars needed', findings: [] };
    }

    const deps = { ...packageJson?.dependencies, ...packageJson?.devDependencies } || {};
    const devDeps = packageJson?.devDependencies || {};
    const scripts = packageJson?.scripts || {};
    const scriptsStr = JSON.stringify(scripts);

    const hasEnvFile = tree.some(p => /(^|\/)\.env(\.|$)/.test(p) && !p.includes('node_modules'));
    const hasDotenvDep = !!(deps.dotenv || deps['@dotenvx/dotenvx'] || deps['dotenv-expand'] || devDeps.dotenv);
    const hasEnvInScripts = /\b(?:NODE_ENV|cross-env|dotenvx|dotenv|env-cmd)\b/.test(scriptsStr);
    const hasTurboJson = tree.some(p => p.endsWith('turbo.json') && !p.includes('node_modules'));
    const hasWrangler = tree.some(p => /wrangler\.(toml|json)$/.test(p) && !p.includes('node_modules'));
    const hasOrmConfig = tree.some(p => !p.includes('node_modules') && /(drizzle|prisma|knexfile|sequelize)\.config\./.test(p));
    const hasWorkspaces = !!packageJson?.workspaces || tree.some(p => p === 'pnpm-workspace.yaml' && !p.includes('node_modules'));
    const subPackages = tree.filter(p => p.endsWith('package.json') && p !== 'package.json' && !p.includes('node_modules'));
    const hasSubPackages = subPackages.length > 0;
    const hasDockerfile = tree.some(p => /(^|\/)Dockerfile$/.test(p) || /(^|\/)docker-compose\.ya?ml$/.test(p));
    const hasServerlessConfig = tree.some(p => /serverless\.(yml|yaml|json)$/.test(p) && !p.includes('node_modules'));
    const hasVercelJson = tree.some(p => p === 'vercel.json' && !p.includes('node_modules'));
    const hasNetlifyToml = tree.some(p => p === 'netlify.toml' && !p.includes('node_modules'));
    const hasFlyToml = tree.some(p => /fly\.toml$/.test(p) && !p.includes('node_modules'));
    const hasDeployScript = ['deploy','preview'].some(k => !!scripts[k]);
    const hasStartScript = !!scripts.start || !!scripts.dev || !!scripts.serve;
    const hasBinField = !!packageJson?.bin;
    const hasBinDir = tree.some(p => /(^|\/)bin\//.test(p) && !p.includes('node_modules') && /\.(js|ts|mjs|cjs)$/.test(p));
    const hasCliFile = tree.some(p => /(^|\/)(cli|cmd|command)\.(js|ts|mjs|cjs)$/.test(p) && !p.includes('node_modules'));
    const isLikelyCli = hasBinField || hasBinDir || hasCliFile;
    const isRunnable = hasStartScript || hasDeployScript || hasDockerfile || isLikelyCli;
    const hasBuildTool = ['webpack','rollup','vite','esbuild','parcel','rspack','next','nuxt','remix','astro','gatsby','sveltekit','babel','typescript','tsup','unbuild','turbo'].some(t => !!deps[t] || !!devDeps[t]);
    const hasFrameworkConfig = tree.some(p => !p.includes('node_modules') && /(next|nuxt|astro|remix|svelte|gatsby|eleventy|nitro)\.config\./.test(p));
    const sourceFileCount = tree.filter(p => /\.(js|ts|jsx|tsx|mjs|cjs)$/.test(p) && !p.includes('node_modules') && !/\.d\.ts$/.test(p)).length;

    const scanLimit = (hasWorkspaces || hasSubPackages) ? 40 : 30;
    const sourceFiles = buildFileList(tree, scanLimit);
    const { foundPattern, foundDotenvSetup } = await scanFiles(sourceFiles, files);

    if (foundPattern) {
      const parts = [];
      if (hasDotenvDep || foundDotenvSetup) parts.push('dotenv configured');
      if (hasEnvFile) parts.push('.env file present');
      return { checkId, status: 'pass', confidence: 'high', message: `Uses environment variables (${parts.join(', ') || foundPattern + ' usage found'})`, findings: [] };
    }

    if (hasTurboJson) {
      const tp = tree.find(p => p.endsWith('turbo.json') && !p.includes('node_modules'));
      if (tp) {
        try {
          const c = await files.get(tp);
          if (c && /"globalEnv"|"env"\s*:/.test(c)) {
            return { checkId, status: 'pass', confidence: 'high', message: 'Uses environment variables (turborepo env config)', findings: [] };
          }
        } catch (e) {}
      }
    }

    if (hasSubPackages) {
      for (const pkg of subPackages.slice(0, 5)) {
        try {
          const c = await files.get(pkg);
          if (c && /\b(?:NODE_ENV|cross-env|dotenvx|dotenv|env-cmd|process\.env)\b/.test(c)) {
            return { checkId, status: 'pass', confidence: 'high', message: 'Uses environment variables (workspace package env usage)', findings: [] };
          }
        } catch (e) {}
      }
    }

    if (hasEnvFile) {
      return { checkId, status: 'pass', confidence: 'high', message: 'Uses environment variables (.env file present)', findings: [] };
    }
    if (hasDotenvDep) {
      return { checkId, status: 'pass', confidence: 'high', message: 'Uses environment variables (dotenv dependency)', findings: [] };
    }
    if (hasEnvInScripts) {
      return { checkId, status: 'pass', confidence: 'high', message: 'Uses environment variables (env referenced in scripts)', findings: [] };
    }
    if (hasWrangler) {
      return { checkId, status: 'pass', confidence: 'high', message: 'Uses environment variables (wrangler config present)', findings: [] };
    }
    if (hasOrmConfig) {
      return { checkId, status: 'pass', confidence: 'high', message: 'Uses environment variables (ORM config present)', findings: [] };
    }

    const shouldCheckHardcoded = (isRunnable || repoType === RepoType.TOOL) && repoType !== RepoType.LIBRARY && repoType !== RepoType.FRAMEWORK;
    if (shouldCheckHardcoded) {
      const cfgPaths = tree.filter(p => {
        if (p.includes('node_modules') || isTestFile(p) || /\.d\.ts$/.test(p)) return false;
        if (!/\.(js|ts|mjs|cjs)$/.test(p)) return false;
        const base = p.split('/').pop().toLowerCase();
        return /(config|configuration|settings|constants|defaults)/.test(base);
      }).sort((a, b) => {
        const sa = scoreFile(a);
        const sb = scoreFile(b);
        if (sb !== sa) return sb - sa;
        return a.split('/').length - b.split('/').length || a.localeCompare(b);
      }).slice(0, 12);

      const findings = [];
      const seen = new Set();

      for (const p of cfgPaths) {
        try {
          const c = await files.get(p);
          if (!c) continue;
          const lines = c.split('\n');
          for (let i = 0; i < lines.length; i++) {
            const line = lines[i].trim();
            if (!line || /^\s*(\/\/|\/\*|\*)/.test(line)) continue;
            const key = `${p}:${i}`;
            if (seen.has(key)) continue;

            const bad =
              /\b(?:baseURL|baseUrl|apiUrl|apiURL|endpoint|host|server|url|base|target|origin|webhook|callback|redirectUri|serviceUrl|apiEndpoint|requestUrl)\s*[:=]\s*[`'"][^'"`\s]*(?:https?:\/\/|(?:[a-z0-9-]+\.)+[a-z]{2,})[^'"`\s]*[`'"]/i.test(line) ||
              /\b(?:region|zone|datacenter|location|availabilityZone|awsRegion|gcpRegion|azureRegion|cluster)\s*[:=]\s*[`'"][\w-]{2,}[`'"]/i.test(line) ||
              /\b(?:timeout|connectTimeout|requestTimeout|readTimeout|writeTimeout|keepAliveTimeout|idleTimeout|maxTimeout|sessionTimeout)\s*[:=]\s*(?:[`'"])?\d{3,6}\b/i.test(line) ||
              /\b(?:port|PORT|serverPort|listenPort|proxyPort)\s*[:=]\s*(?:[`'"])?\d{2,5}\b/.test(line) ||
              /\b(?:apiKey|apiSecret|secretKey|accessKey|authToken|password|secret|token|privateKey)\s*[:=]\s*[`'"][A-Za-z0-9_\-]{12,}[`'"]/.test(line);

            if (bad) {
              findings.push({ file: p, line: i + 1, issue: 'Hardcoded deployment configuration value detected' });
              seen.add(key);
              if (findings.length >= 3) break;
            }
          }
        } catch (e) {}
        if (findings.length >= 3) break;
      }

      if (findings.length >= 2) {
        return { checkId, status: 'check-it', confidence: 'high', message: 'Deployment configuration appears hardcoded; no environment variables detected', findings };
      }
    }

    if (repoType === RepoType.LIBRARY) {
      return { checkId, status: 'not-applicable', confidence: 'medium', message: 'Library — env var usage not required', findings: [] };
    }

    if (repoType === RepoType.FRAMEWORK || repoType === RepoType.TOOL) {
      if (hasBuildTool || sourceFileCount > 10 || hasFrameworkConfig) {
        return { checkId, status: 'pass', confidence: 'medium', message: 'Uses environment variables (framework/tool codebase)', findings: [] };
      }
    }

    if (hasDockerfile || hasServerlessConfig || hasVercelJson || hasNetlifyToml || hasFlyToml) {
      return { checkId, status: 'pass', confidence: 'medium', message: 'Uses environment variables (deployment artifacts present)', findings: [] };
    }

    if (hasDeployScript) {
      return { checkId, status: 'pass', confidence: 'medium', message: 'Uses environment variables (deploy script present)', findings: [] };
    }

    if (hasStartScript || !!packageJson?.bin) {
      return { checkId, status: 'pass', confidence: 'low', message: 'Uses environment variables (runnable entry point)', findings: [] };
    }

    if (hasBuildTool || hasFrameworkConfig) {
      return { checkId, status: 'pass', confidence: 'low', message: 'Uses environment variables (build tooling present)', findings: [] };
    }

    return {
      checkId,
      status: 'check-it',
      confidence: 'medium',
      message: 'No environment variable usage detected',
      findings: [{ file: 'N/A', issue: 'No env var signals found in code, configs, or package metadata' }],
    };

  } catch (err) {
    console.error(err);
    return { checkId, status: 'check-it', confidence: 'low', message: `Error: ${err.message}`, findings: [{ file: 'N/A', issue: err.message }] };
  }
}
